n_hex = "" 
e = 65537

s_hex = "" 

actual_hash = "e7a77fdfc5f03a877459c7a08c3c4e71e4eef9f41f4ea9cb0b3cb3f8c4c8e5dc"

#process
n = int(n_hex, 16)
s = int(s_hex, 16)

em_prime = pow(s, e, n)

em_hex = hex(em_prime)[2:]

#verify

print(f"Decrypted EM (Hex): {em_hex}")
print(f"Actual TBS Hash:    {actual_hash}")

if actual_hash in em_hex:
    print("VERIFICATION SUCCESSFUL: The certificate is valid.")
else:
    print("VERIFICATION FAILED: The certificate might be tampered with.")